# Collect all departure times per category
def all_dep_times\(trains\):
    times = []
    for t in trains:
        for stop in t.get\('tt', []\):
            if 'd' in stop:
                times.append\(stop['d']\)
    return times

def to_minutes\(t\):
    h, m = t.split\(':'\)
    return int\(h\) * 60 + int\(m\)

def from_minutes\(m\):
    return '%02d:%02d' % \(m // 60, m % 60\)

